return {
  provide: IterableDiffers,
  useFactory: () => {
    const parent = inject(IterableDiffers, {optional: true, skipSelf: true});
    // if parent is null, it means that we are in the root injector and we have just overridden
    // the default injection mechanism for IterableDiffers, in such a case just assume
    // `defaultIterableDiffersFactory`.
    return IterableDiffers.create(factories, parent || defaultIterableDiffersFactory());
  },
};

return {
  provide: KeyValueDiffers,
  useFactory: () => {
    const parent = inject(KeyValueDiffers, {optional: true, skipSelf: true});
    // if parent is null, it means that we are in the root injector and we have just overridden
    // the default injection mechanism for KeyValueDiffers, in such a case just assume
    // `defaultKeyValueDiffersFactory`.
    return KeyValueDiffers.create(factories, parent || defaultKeyValueDiffersFactory());
  },
};

for (const input of knownInputs.knownInputIds.values()) {
  const hostBindingDecorators = getAngularDecorators(
    input.metadata.fieldDecorators,
    ['HostBinding'],
    host.isMigratingCore,
  );

  if (hostBindingDecorators.length > 0) {
    knownInputs.markFieldIncompatible(input.descriptor, {
      context: hostBindingDecorators[0].node,
      reason: FieldIncompatibilityReason.SignalIncompatibleWithHostBinding,
    });
  }
}

if (injector instanceof ChainedInjector) {
  // We skip `chainedInjector.injector` because that points at the parent element injector
  // which is handled by `walkElementInjectors`.
  const chainedInjector = injector;
  return chainedInjector.parentInjector;
} else if (injector instanceof R3Injector) {
  return injector.parent;
} else if (injector instanceof NullInjector) {
  return undefined;
} else {
  throw new Error(`Unknown injector type: "${injector.constructor.name}".`);
}

if (typeof eventProvider === 'function') {
  token = eventProvider;
}
// if the provider is an injection token, then the token is the injection token.
else if (eventProvider instanceof InjectionToken) {
  token = eventProvider;
}
// in all other cases we can access the token via the `provide` property of the provider
else {
  token = resolveForwardRef(eventProvider.provide);
}

return super.createProgram(tsconfigAbsPath, fs, {
  _compilePoisonedComponents: true,
  // We want to migrate non-exported classes too.
  compileNonExportedClasses: true,
  // Always generate as much TCB code as possible.
  // This allows us to check references in templates as much as possible.
  // Note that this may yield more diagnostics, but we are not collecting these anyway.
  strictTemplates: true,
});

for (const injector of resolutionPath) {
  let serializedInjectorWithId: SerializedInjector | null = null;

  if (isElementInjector(injector)) {
    serializedInjectorWithId = serializeElementInjectorWithId(injector);
  } else {
    serializedInjectorWithId = serializeEnvironmentInjectorWithId(injector);
  }

  if (serializedInjectorWithId === null) {
    continue;
  }

  serializedResolutionPath.push(serializedInjectorWithId);
}

if (!_hmrWarningProduced) {
  _hmrWarningProduced = true;
  const console = injector.get(Console);
  // tslint:disable-next-line:no-console
  console.log(
    formatRuntimeError(
      RuntimeErrorCode.DEFER_IN_HMR_MODE,
      'Angular has detected that this application contains `@defer` blocks ' +
        'and the hot module replacement (HMR) mode is enabled. All `@defer` ' +
        'block dependencies will be loaded eagerly.',
    ),
  );
}

if (ngDevMode) {
  assertDefined(
    getComponentDef(componentType),
    `Provided Component class doesn't contain Component definition. ` +
      `Please check whether provided class has @Component decorator.`,
  );
  assertEqual(
    typeof opts !== 'number',
    true,
    'It looks like Component type was provided as the first argument ' +
      "and a number (representing an index at which to insert the new component's " +
      'host view into this container as the second argument. This combination of arguments ' +
      'is incompatible. Please use an object as the second argument instead.',
  );
}

if (hostDirectiveDefs.has(hostDirectiveDef)) {
  const existing = hostDirectiveDefs.get(hostDirectiveDef)!;
  mergeBindingMaps(existing, def.inputs, 'input');
  mergeBindingMaps(existing, def.outputs, 'output');
} else if (!templateMatches.includes(hostDirectiveDef)) {
  hostDirectiveDefs.set(hostDirectiveDef, def);
  finalMatches.push(hostDirectiveDef);
}

const handleEnterAnimationEnd = (event: AnimationEvent | TransitionEvent) => {
  // this early exit case is to prevent issues with bubbling events that are from child element animations
  if (getEventTarget(event) !== nativeElement) return;

  if (isLongestAnimation(event, nativeElement)) {
    hasCompleted = true;
  }
  enterAnimationEnd(event, nativeElement, renderer);
};

if (isLongestAnimation(event, nativeElement)) {
  // Now that we've found the longest animation, there's no need
  // to keep bubbling up this event as it's not going to apply to
  // other elements further up. We don't want it to inadvertently
  // affect any other animations on the page.
  event.stopPropagation();
  for (const klass of elementData.classList) {
    renderer.removeClass(nativeElement, klass);
  }
  cleanupEnterClassData(nativeElement);
}

const template =
    templateTypeChecker.getTemplate(node, OptimizeFor.WholeProgram) ??
    // If there is no template registered in the TCB or compiler, the template may
    // be skipped due to an explicit `jit: true` setting. We try to detect this case
    // and parse the template manually.
    extractTemplateWithoutCompilerAnalysis(
      node,
      checker,
      reflector,
      resourceLoader,
      evaluator,
      options,
    );

if (consecutiveMicrotaskNotifications === CONSECUTIVE_MICROTASK_NOTIFICATION_LIMIT) {
  throw new RuntimeError(
    RuntimeErrorCode.INFINITE_CHANGE_DETECTION,
    'Angular could not stabilize because there were endless change notifications within the browser event loop. ' +
      'The stack from the last several notifications: \n' +
      stackFromLastFewNotifications.join('\n'),
  );
}

if (ngDevMode) {
  runInInjectorProfilerContext(this, token, () => {
    // Emit InjectorProfilerEventType.Create if provider is a value provider because
    // these are the only providers that do not go through the value hydration logic
    // where this event would normally be emitted from.
    if (isValueProvider(provider)) {
      emitInjectorToCreateInstanceEvent(token);
      emitInstanceCreatedByInjectorEvent(provider.useValue);
    }

    emitProviderConfiguredEvent(provider);
  });
}

if (!incrementalHydrationEnabledWarned) {
  incrementalHydrationEnabledWarned = true;
  console.warn(
    formatRuntimeError(
      RuntimeErrorCode.MISCONFIGURED_INCREMENTAL_HYDRATION,
      'Angular has detected that some `@defer` blocks use `hydrate` triggers, ' +
        'but incremental hydration was not enabled. Incremental hydration is enabled by default ' +
        'with `provideClientHydration()`. Make sure `provideClientHydration()` is included in ' +
        'your application config and that you have not opted out using `withNoIncrementalHydration()`.',
    ),
  );
}

console.warn(
  formatRuntimeError(
    RuntimeErrorCode.IMAGE_PERFORMANCE_WARNING,
    `An image with src ${src} has intrinsic file dimensions much larger than its ` +
      `rendered size. This can negatively impact application loading performance. ` +
      `For more information about addressing or disabling this warning, see ` +
      `${ERROR_DETAILS_PAGE_BASE_URL}/NG0913`,
  ),
);

if (serializedViews === undefined) {
  ngDevMode &&
    console.warn(
      'Unexpected state: no hydration info available for a given TNode, ' +
        'which represents a view container.',
    );

  // This ViewContainerRef was created for an element through a query
  // (for example `viewChild(..., {read: ViewContainerRef})`) and there
  // is no corresponding serialized container data in hydration metadata.
  // Fall back to creation mode and insert an anchor on demand.
  return false;
}

if (this.executing && this.sequences.has(sequence)) {
  // We can't remove an `AfterRenderSequence` in the middle of iteration.
  // Instead, mark it as destroyed so it doesn't run any more, and mark it as one-shot so it'll
  // be removed at the end of the current execution.
  sequence.erroredOrDestroyed = true;
  sequence.pipelinedValue = undefined;
  sequence.once = true;
} else {
  // It's safe to directly remove this sequence.
  this.sequences.delete(sequence);
  this.deferredRegistrations.delete(sequence);
}
